// NewTriggerPayload builds a adminRiskAnalysis service trigger endpoint
// payload.
func NewTriggerPayload(body *TriggerRequestBody, sessionToken *string) *adminriskanalysis.TriggerPayload {
	v := &adminriskanalysis.TriggerPayload{
		ProjectID:    *body.ProjectID,
		RiskPolicyID: *body.RiskPolicyID,
		From:         *body.From,
		To:           body.To,
	}
	v.SessionToken = sessionToken

	return v
}

// NewStatusPayload builds a adminRiskAnalysis service status endpoint payload.
func NewStatusPayload(projectID string, sessionToken *string) *adminriskanalysis.StatusPayload {
	v := &adminriskanalysis.StatusPayload{}
	v.ProjectID = projectID
	v.SessionToken = sessionToken

	return v
}

// ValidateTriggerRequestBody runs the validations defined on TriggerRequestBody
func ValidateTriggerRequestBody(body *TriggerRequestBody) (err error) {
	if body.ProjectID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("project_id", "body"))
	}
	if body.RiskPolicyID == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("risk_policy_id", "body"))
	}
	if body.From == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("from", "body"))
	}
	if body.ProjectID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.project_id", *body.ProjectID, goa.FormatUUID))
	}
	if body.RiskPolicyID != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.risk_policy_id", *body.RiskPolicyID, goa.FormatUUID))
	}
	if body.From != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.from", *body.From, goa.FormatDateTime))
	}
	if body.To != nil {
		err = goa.MergeErrors(err, goa.ValidateFormat("body.to", *body.To, goa.FormatDateTime))
	}
	return
}
